-- CATALOG ENGINE / backend-ready / TEST locale
PRAGMA foreign_keys = OFF;
BEGIN TRANSACTION;
DROP TABLE IF EXISTS catalog_engine_kites;
CREATE TABLE catalog_engine_kites (
    catalog_id INTEGER PRIMARY KEY AUTOINCREMENT,
    brand TEXT,
    model TEXT,
    series TEXT,
    year_raw TEXT,
    year_start INTEGER,
    year_end INTEGER,
    discipline TEXT,
    catalog_scope TEXT,
    general_guardrail_ok INTEGER,
    size_m2 REAL,
    kite_weight_kg REAL,
    wind_min_kts REAL,
    wind_max_kts REAL,
    source_type TEXT,
    source_url TEXT,
    backend_use TEXT,
    note TEXT,
    wind_mid_kts REAL GENERATED ALWAYS AS ((wind_min_kts + wind_max_kts) / 2.0) VIRTUAL,
    wind_range_kts REAL GENERATED ALWAYS AS (wind_max_kts - wind_min_kts) VIRTUAL
);
CREATE INDEX idx_catalog_engine_kites_brand_model_size ON catalog_engine_kites(brand, model, size_m2);
CREATE INDEX idx_catalog_engine_kites_guardrail ON catalog_engine_kites(general_guardrail_ok, backend_use);
CREATE INDEX idx_catalog_engine_kites_wind ON catalog_engine_kites(wind_min_kts, wind_max_kts);
COMMIT;